import java.util.List;

final class LoopSquares {
    /** Single unbox per element, no Spliterator, no pipeline. */
    long sumSquares(List<Integer> values) {
        long sum = 0;
        for (int v : values) {
            sum += (long) v * v;
        }
        return sum;
    }
}

