final class ColorCodec {
    int packArgb(int r, int g, int b) {
        return (0xFF << 24) | (r << 16) | (g << 8) | b;
    }

    int red(int argb)   { return (argb >>> 16) & 0xFF; }
    int green(int argb) { return (argb >>> 8) & 0xFF; }
    int blue(int argb)  { return argb & 0xFF; }
}

