final class PhysicsEscape {
    Vector3 calculateForce(Vector3 v, double m, Vector3 a) {
        Vector3 momentum = v.mul(m);
        Vector3 force = momentum.add(a.mul(m));
        return force; // chain creates transient escaping objects
    }
}

